# GraphQL Schema
type_defs = """
    type Query {
        me: User
        user(id: ID!): User
        users: [User!]!
        post(id: ID!): Post
        posts(authorId: ID, publishedOnly: Boolean): [Post!]!
    }

    type User {
        id: ID!
        username: String!
        bio: String
        email: String
        phone: String
        address: String
        posts: [Post!]!
        postCount: Int!
    }

    type Post {
        id: ID!
        title: String!
        content: String!
        published: Boolean!
        author: User!
    }
"""

# Resolvers
query = QueryType()
user_type = ObjectType("User")
post_type = ObjectType("Post")


@query.field("me")
def resolve_me(_, info):
    current_user = info.context.get("current_user")
    if current_user is None:
        return None
    return USERS.get(current_user["id"])


@query.field("user")
def resolve_user(_, info, id):
    return USERS.get(id)


@query.field("users")
def resolve_users(_, info):
    return list(USERS.values())


@query.field("post")
def resolve_post(_, info, id):
    return POSTS.get(id)


@query.field("posts")
def resolve_posts(_, info, authorId=None, publishedOnly=None):
    results = list(POSTS.values())

    if authorId is not None:
        results = [p for p in results if p.author_id == authorId]

    if publishedOnly:
        results = [p for p in results if p.published]

    return results


# User field resolvers
@user_type.field("posts")
def resolve_user_posts(user, info):
    return [POSTS[pid] for pid in user.post_ids if pid in POSTS]


@user_type.field("postCount")
def resolve_user_post_count(user, info):
    return len(user.post_ids)


@user_type.field("email")
def resolve_user_email(user, info):
    """Resolve email - field-level permissions can be added later."""
    return user.email


@user_type.field("phone")
def resolve_user_phone(user, info):
    """Resolve phone - field-level permissions can be added later."""
    return user.phone


@user_type.field("address")
def resolve_user_address(user, info):
    """Resolve address - field-level permissions can be added later."""
    return user.address


# Post field resolvers
@post_type.field("author")
def resolve_post_author(post, info):
    return USERS.get(post.author_id)


# Create executable schema
schema = make_executable_schema(type_defs, query, user_type, post_type)


# ASGI app with authentication middleware
async def graphql_endpoint(request: Request):
    """Handle GraphQL requests with context building."""
    data = await request.json()

    # Build context with current_user from middleware/auth
    context = {
        "request": request,
        "current_user": getattr(request.state, "current_user", None),
    }

    success, result = graphql_sync(
        schema,
        data,
        context_value=context,
        debug=True,
    )

    status_code = 200 if success else 400
    return JSONResponse(result, status_code=status_code)


class AuthenticationMiddleware:
    """
    Simple authentication middleware that checks for an Authorization header.
    In a real app, this would validate JWT tokens, session cookies, etc.

    For demo purposes:
    - Header "Authorization: Bearer user-1" authenticates as user 1 (alice)
    - Header "Authorization: Bearer user-2" authenticates as user 2 (bob)
    - Header "Authorization: Bearer user-3" authenticates as user 3 (charlie)
    - No header or invalid header means unauthenticated
    """

    def __init__(self, app):
        self.app = app

    async def __call__(self, scope, receive, send):
        if scope["type"] == "http":
            from starlette.requests import Request
            request = Request(scope, receive)

            auth_header = request.headers.get("Authorization", "")
            current_user = None

            if auth_header.startswith("Bearer user-"):
                try:
                    user_id = auth_header.split("Bearer user-")[1]
                    if user_id in USERS:
                        user = USERS[user_id]
                        current_user = {
                            "id": user.id,
                            "username": user.username,
                        }
                except (IndexError, KeyError):
                    pass

            scope["state"] = {"current_user": current_user}

        await self.app(scope, receive, send)


# Build the Starlette app
app = Starlette(
    routes=[
        Route("/graphql", graphql_endpoint, methods=["POST"]),
    ],
    middleware=[
        Middleware(AuthenticationMiddleware),
    ],
)


